#define DEFAULT_ORDER 508

typedef struct {
    int value;
} record;

typedef struct {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    char is_leaf;
    int num_keys;
} knode;

kernel void findK(
    long maxheight,
    const global knode *knodes,
    long knodes_elem,
    const global record *records,
    global long *currKnode,
    global long *offset,
    global int *keys,
    global record *ans)
{
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int threadsPerBlock = get_local_size(0);

    long current_offset = offset[bid];
    long current_knode = currKnode[bid];
    int key_val = keys[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[current_knode].keys[thid] <= key_val) && 
                (knodes[current_knode].keys[thid + 1] > key_val)) {

                if (knodes[current_offset].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
        }
        current_knode = current_offset;
    }

    if (thid < threadsPerBlock) {
        if (knodes[current_knode].keys[thid] == key_val) {
            ans[bid].value = records[knodes[current_knode].indices[thid]].value;
        }
    }
}

