    global long *lastKnode,
    global long *offset_2,
    global int *start,
    global int *end,
    global int *recstart,
    global int *reclength)
{
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int threadsPerBlock = get_local_size(0);

    long current_offset = offset[bid];
    long current_knode = currKnode[bid];
    long last_offset = offset_2[bid];
    long last_knode = lastKnode[bid];

    int start_val = start[bid];
    int end_val = end[bid];

    for (int i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            if ((knodes[current_knode].keys[thid] <= start_val) && 
                (knodes[current_knode].keys[thid + 1] > start_val)) {

                if (knodes[current_knode].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_knode].indices[thid];
                }
            }

            if ((knodes[last_knode].keys[thid] <= end_val) && 
                (knodes[last_knode].keys[thid + 1] > end_val)) {

                if (knodes[last_knode].indices[thid] < knodes_elem) {
                    last_offset = knodes[last_knode].indices[thid];
                }
            }
        }
